const item = $input.first().json;

// Get data and turn it into an object if it's a JSON string
let data = item.data;

if (typeof data === 'string') {
  try {
    data = JSON.parse(data);
  } catch (error) {
    throw new Error('data is not valid JSON: ' + data);
  }
} else if (!data || typeof data !== 'object') {
  data = {};
}

// Pull out first file for the signature
const file0 = (data.file && data.file[0]) || {};

const output = {
  ...item,      // keep original fields (guest_data, is_form_submitted, etc.)
  ...data,      // expand fields from parsed data
  signatureUrl: file0.presignedUrl || null,
};

// Optional: remove nested data now that it's expanded
delete output.data;

return [
  {
    json: output,
  },
];

const baseUrl = 'https://ashleymartinnz.zenoti.com/Appointment/appointmentcustomdatav2.aspx';

// Pull values from previous nodes
const AppGroupId    = $('When Executed by Another Workflow').first().json.body.data.appointment_group_id;
const ServiceId     = $('When Executed by Another Workflow').first().json.body.data.appointments[0].service_id;
const ServiceName   = $('When Executed by Another Workflow').first().json.body.data.appointments[0].service_name;
const GuestId       = $('When Executed by Another Workflow').first().json.body.data.guest.id;
const AppointmentId = $('When Executed by Another Workflow').first().json.body.data.appointments[0].id;

// Helper to build querystring with encoding
function qs(params) {
  return Object.keys(params)
    .filter((k) => params[k] !== undefined && params[k] !== null && params[k] !== '')
    .map((k) => `${encodeURIComponent(k)}=${encodeURIComponent(String(params[k]))}`)
    .join('&');
}

const query = qs({
  AppGroupId,
  ServiceId,
  Service: ServiceName,
  GuestId,
  AppointmentId,
});

const finalUrl = `${baseUrl}?${query}`;

return [
  {
    json: {
      AppointmentCustomDataUrl: finalUrl,
    },
  },
];

const item = $input.first().json;

// Get data and turn it into an object if it's a JSON string
let data = item.data;

if (typeof data === 'string') {
  try {
    data = JSON.parse(data);
  } catch (error) {
    throw new Error('data is not valid JSON: ' + data);
  }
} else if (!data || typeof data !== 'object') {
  data = {};
}

// Pull out first file for the signature
const file0 = (data.file && data.file[0]) || {};

const output = {
  ...item,      // keep original fields (guest_data, is_form_submitted, etc.)
  ...data,      // expand fields from parsed data
  signatureUrl: file0.presignedUrl || null,
};

// Optional: remove nested data now that it's expanded
delete output.data;

return [
  {
    json: output,
  },
];

const items = $input.all();

// Field we are reading from
const targetField = "product";

function formatNumber(numStr) {
  if (numStr.length < 3) {
    return numStr + "%";
  }
  const first = numStr[0];
  const rest = numStr.slice(1);
  return `${first}.${rest}%`;
}

for (const item of items) {
  const raw = item.json[targetField];

  if (typeof raw === "string" && raw.length > 0) {

    const parts = raw.match(/[A-Z][a-z]*|[0-9]+/g) || [];

    const transformed = parts.map(p => {
      if (/^\d+$/.test(p)) {
        return formatNumber(p);
      }
      return p;
    });

    item.json["ProductNameCleaned"] = transformed.join(" ");

    if (/finasteride/i.test(raw)) {
      item.json["ZenotiProductName"] = "Minoxidil + Finasteride Solution";
    } else {
      item.json["ZenotiProductName"] = "Minoxidil Solution";
    }

    // NEW — first 5 chars
    item.json["ZenotiProductNameShort"] = item.json["ZenotiProductName"].slice(0, 5);

    // NEW — last 5 chars
    const zName = item.json["ZenotiProductName"];
    item.json["ZenotiProductNameEnd"] = zName.slice(-4);

  } else {
    item.json["ProductNameCleaned"] = "";
    item.json["ZenotiProductName"] = "";
    item.json["ZenotiProductNameShort"] = "";
    item.json["ZenotiProductNameEnd"] = "";
  }
}

return items;

const items = $input.all();
const empty = items.length === 1 && Object.keys(items[0].json).length === 0;

// Add the flag to the first (or only) item
if (items.length > 0) {
  items[0].json.empty = empty;
  return items;
}

// If nothing came in, emit one with just the flag
return [{ json: { empty: true } }];

// Items we want to OUTPUT (all fields kept)
const drugItems = $('Clean up Drug Name').all();

// Previous node items (where balance lives)
const balanceItems = $input.all();

const output = [];

for (let i = 0; i < drugItems.length; i++) {
  const drugItem = drugItems[i];

  // Clone so we don't accidentally mutate shared references
  const item = {
    json: { ...drugItem.json },
  };

  // Get balance from previous node (same index if possible, else first one)
  const balanceRaw = balanceItems[i]
    ? balanceItems[i].json.balance
    : (balanceItems[0]?.json.balance ?? 0);

  // Quantity comes from Clean up Drug Name
  const qtyRaw = drugItem.json.quantity;

  // Make sure they're numbers
  const balance = Number(balanceRaw) || 0;
  const quantity = Number(qtyRaw) || 0;

  // Do the maths
  const remaining = balance - quantity;

  // Add new fields
  item.json.CanSubtract = remaining >= 0;
  item.json.RemainingBalance = remaining;
  item.json.ProductID = $input.first().json.product_type_info.id;

  output.push(item);
}

// Return ALL Clean up Drug Name fields + new maths fields
return output;

const agg = $input.first()?.json ?? {};
const products = Array.isArray(agg.products) ? agg.products : [];

// 1) No product groups
if (products.length === 0) {
  return [{
    json: {
      FilterMeOut: true,
      FilterReason: "NoProducts",
    }
  }];
}

// 2) Multiple product groups = duplicate data
if (products.length > 1) {
  return [{
    json: {
      FilterMeOut: true,
      FilterReason: "DuplicateProductGroups",
      GroupCount: products.length,
    }
  }];
}

// 3) Exactly ONE product group → PASS
return [{
  json: {
    FilterMeOut: false,
    FilterReason: "OK",
    products: products[0], // unwrap ONE level
  }
}];

const baseUrl = 'https://ashleymartinnz.zenoti.com/Appointment/appointmentcustomdatav2.aspx';

// Pull values from previous nodes
const AppGroupId    = $('Clinic Previous Day Appointments').first().json.appointment_group_id;
const ServiceId     = $('Loop Over Items').first().json.service.id
const ServiceName   = $('Get Appointment Forms').first().json.service_name;
const GuestId       = $('Guest Details').first().json.id;
const AppointmentId = $('Format Data').first().json.AppointmentID;

// Helper to build querystring with encoding
function qs(params) {
  return Object.keys(params)
    .filter((k) => params[k] !== undefined && params[k] !== null && params[k] !== '')
    .map((k) => `${encodeURIComponent(k)}=${encodeURIComponent(String(params[k]))}`)
    .join('&');
}

const query = qs({
  AppGroupId,
  ServiceId,
  Service: ServiceName,
  GuestId,
  AppointmentId,
});

const finalUrl = `${baseUrl}?${query}`;

return [
  {
    json: {
      AppointmentCustomDataUrl: finalUrl,
    },
  },
];

// Get all incoming items
const items = $input.all();

for (const item of items) {
  const boxes = item.json.selectBoxes || {};

  // Work out which option is true
  if (boxes.clinic) {
    item.json.DeliveryLocation = 'clinic';
  } else if (boxes.guest) {
    item.json.DeliveryLocation = 'guest';
  } else if (boxes.custom) {
    item.json.DeliveryLocation = 'custom';
  } else {
    item.json.DeliveryLocation = 'unknown';
  }
}

// Pass everything through with the new field added
return items;
